// src/components/IconButton.tsx
import { save } from "../lib/actions.ts";

// DAP: arbitrary/magic Tailwind values (px-[13px], py-[7px], mt-[23px]) instead of the
// spacing scale; hardcoded hex colors instead of design tokens; NO hover/focus/disabled
// states; and an icon-only button with NO aria-label (inaccessible name).
export function IconButton() {
  return (
    <button
      className="px-[13px] py-[7px] mt-[23px] rounded"
      style={{ color: "#3a7bd5", background: "#eeeeee" }}
      onClick={() => save()}
    >
      <svg width="16" height="16" viewBox="0 0 16 16">
        <path d="M2 8l4 4 8-8" />
      </svg>
    </button>
  );
}

// src/components/IconButton.tsx
import { save } from "../lib/actions.ts";

// Consistent: spacing scale tokens (px-3/py-2/mt-6), semantic color tokens, full interactive
// states (hover/focus-visible/disabled), and an accessible name (aria-label) with the
// decorative icon hidden from the a11y tree.
export function IconButton() {
  return (
    <button
      type="button"
      aria-label="Save"
      className="px-3 py-2 mt-6 rounded text-primary bg-surface hover:bg-surface-hover focus-visible:ring-2 focus-visible:ring-primary disabled:opacity-50 disabled:pointer-events-none"
      onClick={() => save()}
    >
      <svg width="16" height="16" viewBox="0 0 16 16" aria-hidden="true">
        <path d="M2 8l4 4 8-8" />
      </svg>
    </button>
  );
}
